--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -750,6 +750,7 @@ static Instruction *shrinkInsertElt(CastInst &Trunc,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
   if (Instruction *Result = commonCastTransforms(Trunc))
     return Result;
@@ -804,6 +805,55 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
   if (DestWidth == 1) {
     Value *Zero = Constant::getNullValue(SrcTy);

+    // Pattern: trunc (lshr X, SrcWidth-1) to i1 -> icmp slt X, 0
+    // Additionally, if the trunc is used in a xor with true and then in a
+    // select with the same icmp as true value and false as false value,
+    // replace the select with false.
+    {
+      Value *X;
+      if (match(Src, m_LShr(m_Value(X), m_SpecificInt(SrcWidth - 1)))) {
+        // Look for existing icmp slt X, 0
+        Value *ICmp = nullptr;
+        for (User *U : X->users()) {
+          if (auto *CI = dyn_cast<ICmpInst>(U)) {
+            if (CI->getPredicate() == ICmpInst::ICMP_SLT &&
+                match(CI->getOperand(1), m_Zero())) {
+              ICmp = CI;
+              break;
+            }
+          }
+        }
+        if (!ICmp)
+          ICmp = Builder.CreateICmpSLT(X, ConstantInt::getNullValue(SrcTy));
+
+        // Collect the users of the trunc that are xor with true (i.e., not)
+        SmallVector<Instruction *, 2> XorUsers;
+        for (User *U : Trunc.users()) {
+          if (BinaryOperator *Xor = dyn_cast<BinaryOperator>(U)) {
+            if (match(Xor, m_Xor(m_Specific(&Trunc), m_One())))
+              XorUsers.push_back(Xor);
+          }
+        }
+
+        // For each such xor, look for a select that uses it and matches the
+        // pattern.
+        for (Instruction *Xor : XorUsers) {
+          for (User *SU : Xor->users()) {
+            if (SelectInst *Select = dyn_cast<SelectInst>(SU)) {
+              if (Select->getCondition() == Xor &&
+                  Select->getFalseValue() == ConstantInt::getFalse(DestTy) &&
+                  Select->getTrueValue() == ICmp) {
+                replaceInstUsesWith(*Select, ConstantInt::getFalse(DestTy));
+                // We don't break because there might be multiple selects.
+              }
+            }
+          }
+        }
+
+        return replaceInstUsesWith(Trunc, ICmp);
+      }
+    }
+
     Value *X;
     const APInt *C1;
     Constant *C2;
@@ -962,6 +1012,7 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
   return Changed ? &Trunc : nullptr;
 }

